-- Catppuccin - Colorscheme
-- https://github.com/catppuccin/nvim

return {
  'catppuccin/nvim',
  name = 'catppuccin',
  priority = 1000, -- Make sure to load this before all the other start plugins.
  config = function()
    require('catppuccin').setup {
      flavour = 'mocha', -- Set to Mocha variant (latte, frappe, macchiato, mocha)
      -- transparent_background = true, -- Enable transparency to match terminal opacity
      styles = {
        comments = {}, -- No special styling for comments (removes italics)
      },
      background = {
        light = 'latte',
        dark = 'mocha',
      },
    }
    -- Load the Catppuccin colorscheme
    vim.cmd.colorscheme 'catppuccin'
  end,
}

-- Markview.nvim - Highly customizable markdown, LaTeX, and Typst previewer
-- https://github.com/OXY2DEV/markview.nvim

return {
  'OXY2DEV/markview.nvim',
  lazy = false, -- Recommended to prevent lazy-loading for proper initialization
  dependencies = {
    'nvim-treesitter/nvim-treesitter',
  },
  opts = {
    -- Enable for markdown and HTML files
    filetypes = { 'markdown', 'html' },
    modes = { 'n', 'no', 'c' }, -- Preview in normal, operator-pending, and command modes
    -- Use default settings for all other options
  },
}

-- Telescope - Fuzzy Finder (files, lsp, etc)
-- https://github.com/nvim-telescope/telescope.nvim

return {
  'nvim-telescope/telescope.nvim',
  event = 'VimEnter',
  dependencies = {
    'nvim-lua/plenary.nvim',
    {
      'nvim-telescope/telescope-fzf-native.nvim',
      build = 'make',
      cond = function()
        return vim.fn.executable 'make' == 1
      end,
    },
    { 'nvim-telescope/telescope-ui-select.nvim' },
    { 'nvim-tree/nvim-web-devicons', enabled = vim.g.have_nerd_font },
  },
  config = function()
    -- [[ Configure Telescope ]]
    -- See `:help telescope` and `:help telescope.setup()`
    require('telescope').setup {
      -- You can put your default mappings / updates / etc. in here
      --  All the info you're looking for is in `:help telescope.setup()`
      --
      defaults = {
        vimgrep_arguments = {
          'rg',
          '--color=never',
          '--no-heading',
          '--with-filename',
          '--line-number',
          '--column',
          '--smart-case',
          '--hidden', -- Include hidden files
          '--glob',
          '!.git/*', -- Exclude .git directory
        },
      },
      pickers = {
        find_files = {
          -- Show hidden files in find_files picker
          hidden = true,
          -- Optionally, you can add file_ignore_patterns here if needed
          -- file_ignore_patterns = { '.git/', 'node_modules/' },
        },
      },
      extensions = {
        ['ui-select'] = {
          require('telescope.themes').get_dropdown(),
        },
      },
    }

    -- Enable Telescope extensions if they are installed
    pcall(require('telescope').load_extension, 'fzf')
    pcall(require('telescope').load_extension, 'ui-select')

    -- See `:help telescope.builtin`
    local builtin = require 'telescope.builtin'
    vim.keymap.set('n', '<leader>sh', builtin.help_tags, { desc = '[S]earch [H]elp' })
    vim.keymap.set('n', '<leader>sk', builtin.keymaps, { desc = '[S]earch [K]eymaps' })
    vim.keymap.set('n', '<leader>sf', builtin.find_files, { desc = '[S]earch [F]iles' })
    vim.keymap.set('n', '<leader>ss', builtin.builtin, { desc = '[S]earch [S]elect Telescope' })
    vim.keymap.set('n', '<leader>sw', builtin.grep_string, { desc = '[S]earch current [W]ord' })
    vim.keymap.set('n', '<leader>sg', builtin.live_grep, { desc = '[S]earch by [G]rep' })
    vim.keymap.set('n', '<leader>sd', builtin.diagnostics, { desc = '[S]earch [D]iagnostics' })
    vim.keymap.set('n', '<leader>sr', builtin.resume, { desc = '[S]earch [R]esume' })
    vim.keymap.set('n', '<leader>s.', builtin.oldfiles, { desc = '[S]earch Recent Files ("." for repeat)' })
    vim.keymap.set('n', '<leader><leader>', builtin.buffers, { desc = '[ ] Find existing buffers' })

    -- Slightly advanced example of overriding default behavior and theme
    vim.keymap.set('n', '<leader>/', function()
      -- You can pass additional configuration to Telescope to change the theme, layout, etc.
      builtin.current_buffer_fuzzy_find(require('telescope.themes').get_dropdown {
        winblend = 10,
        previewer = false,
      })
    end, { desc = '[/] Fuzzily search in current buffer' })

    -- It's also possible to pass additional configuration options.
    --  See `:help telescope.builtin.live_grep()` for information about particular keys
    vim.keymap.set('n', '<leader>s/', function()
      builtin.live_grep {
        grep_open_files = true,
        prompt_title = 'Live Grep in Open Files',
      }
    end, { desc = '[S]earch [/] in Open Files' })

    -- Shortcut for searching your Neovim configuration files
    vim.keymap.set('n', '<leader>sn', function()
      builtin.find_files { cwd = vim.fn.stdpath 'config' }
    end, { desc = '[S]earch [N]eovim files' })
  end,
}

-- Snacks.nvim - A collection of small QoL plugins for Neovim
-- https://github.com/folke/snacks.nvim

return {
  'folke/snacks.nvim',
  priority = 1000,
  lazy = false,
  opts = {
    -- Enable specific features
    bigfile = { enabled = true }, -- Better performance for large files
    notifier = { enabled = true }, -- Pretty notifications (replaces fidget.nvim)
    quickfile = { enabled = true }, -- Faster file loading
    statuscolumn = { enabled = false }, -- We're using default for now
    words = { enabled = true }, -- Enhanced LSP reference highlighting

    -- Smooth scrolling animations
    scroll = {
      enabled = true,
      animate = {
        duration = { step = 15, total = 150 },
        easing = 'linear',
      },
    },

    -- Better buffer deletion
    bufdelete = {
      enabled = true,
    },

    -- Smart file renaming with LSP integration
    rename = {
      enabled = true,
    },

    -- Configure notifier (replaces fidget.nvim)
    notifier_opts = {
      timeout = 3000,
      width = { min = 40, max = 0.4 },
      height = { min = 1, max = 0.6 },
      margin = { top = 0, right = 1, bottom = 0 },
      icons = {
        error = "󰅚 ",
        warn = "󰀪 ",
        info = "󰋽 ",
        debug = "󰠭 ",
        trace = "󰏫 ",
      },
    },
  },
  keys = {
    -- Notification history
    { '<leader>sn', function() require('snacks').notifier.show_history() end, desc = 'Show notification history' },

    -- Buffer deletion
    { '<leader>bd', function() require('snacks').bufdelete.delete() end, desc = 'Delete buffer' },
    { '<leader>bo', function() require('snacks').bufdelete.other() end, desc = 'Delete other buffers' },

    -- Smart rename
    { '<leader>rn', function() require('snacks').rename.rename_file() end, desc = 'Rename file' },

    -- Dismiss notifications
    { '<leader>nd', function() require('snacks').notifier.hide() end, desc = 'Dismiss all notifications' },
  },
  init = function()
    -- Override vim.notify with snacks notifier
    vim.notify = function(msg, level, opts)
      require('snacks').notifier.notify(msg, level, opts)
    end
  end,
}

