} from '../schemas';

const c = initContract();

export const pointsContract = c.router({
  getPoints: {
    method: 'GET',
    path: '/points',
    query: z.object({
      userId: z.string().uuid().optional(),
      householdId: z.string().uuid().optional(),
      skip: z.coerce.number().optional(),
      take: z.coerce.number().optional(),
    }),
    responses: {
      200: c.type<Points[]>(),
    },
    summary: 'Get points records',
  },
  getLeaderboard: {
    method: 'GET',
    path: '/points/leaderboard',
    query: z.object({
      householdId: z.string().uuid(),
      period: LeaderboardPeriodSchema.default('week'),
    }),
    responses: {
      200: c.type<LeaderboardEntry[]>(),
    },
    summary: 'Get leaderboard for a household',
  },
  getUserPoints: {
    method: 'GET',
    path: '/points/user/:userId',
    pathParams: z.object({
      userId: z.string().uuid(),
    }),
    query: z.object({
      householdId: z.string().uuid().optional(),
      period: LeaderboardPeriodSchema.optional(),
    }),
    responses: {
      200: c.type<{ totalPoints: number; records: Points[] }>(),
    },
    summary: 'Get total points and history for a user',
  },
});

