return {
  'stevearc/oil.nvim',
  dependencies = { 'nvim-tree/nvim-web-devicons' },
  lazy = false,
  config = function()
    require('oil').setup {
      view_options = {
        show_hidden = true,
      },
      delete_to_trash = true,
      skip_confirm_for_simple_edits = true,
    }
    vim.keymap.set('n', '-', '<CMD>Oil<CR>', { desc = 'Open parent directory' })
  end,
}

return {
  'wnkz/monoglow.nvim',
  lazy = false,
  priority = 1000,
  opts = {},
  config = function(_, opts)
    require('monoglow').setup(opts)
    vim.cmd.colorscheme 'monoglow'
  end,
}

-- Neo-tree is a Neovim plugin to browse the file system
-- https://github.com/nvim-neo-tree/neo-tree.nvim

return {
  'nvim-neo-tree/neo-tree.nvim',
  version = '*',
  dependencies = {
    'nvim-lua/plenary.nvim',
    'nvim-tree/nvim-web-devicons', -- not strictly required, but recommended
    'MunifTanjim/nui.nvim',
  },
  lazy = false,
  keys = {
    { '\\', ':Neotree reveal<CR>', desc = 'NeoTree reveal', silent = true },
  },
  opts = {
    filesystem = {
      filtered_items = {
        visible = true, -- Show hidden files by default
        hide_dotfiles = false, -- Don't hide dotfiles
        hide_gitignored = false, -- Optionally show gitignored files
        hide_by_name = {
          '.git', -- Still hide .git folder as it's usually not needed
        },
      },
      window = {
        mappings = {
          ['\\'] = 'close_window',
          ['H'] = 'toggle_hidden', -- Add toggle for hidden files
        },
      },
    },
  },
}

-- Snacks.nvim - A collection of small QoL plugins for Neovim
-- https://github.com/folke/snacks.nvim

return {
  'folke/snacks.nvim',
  priority = 1000,
  lazy = false,
  opts = {
    -- Enable specific features
    bigfile = { enabled = true }, -- Better performance for large files
    notifier = { enabled = true }, -- Pretty notifications (replaces fidget.nvim)
    quickfile = { enabled = true }, -- Faster file loading
    statuscolumn = { enabled = false }, -- We're using default for now
    words = { enabled = true }, -- Enhanced LSP reference highlighting

    -- Smooth scrolling animations
    scroll = {
      enabled = true,
      animate = {
        duration = { step = 15, total = 150 },
        easing = 'linear',
      },
    },

    -- Better buffer deletion
    bufdelete = {
      enabled = true,
    },

    -- Smart file renaming with LSP integration
    rename = {
      enabled = true,
    },

    -- Configure notifier (replaces fidget.nvim)
    notifier_opts = {
      timeout = 3000,
      width = { min = 40, max = 0.4 },
      height = { min = 1, max = 0.6 },
      margin = { top = 0, right = 1, bottom = 0 },
      icons = {
        error = "󰅚 ",
        warn = "󰀪 ",
        info = "󰋽 ",
        debug = "󰠭 ",
        trace = "󰏫 ",
      },
    },
  },
  keys = {
    -- Notification history
    { '<leader>sn', function() require('snacks').notifier.show_history() end, desc = 'Show notification history' },

    -- Buffer deletion
    { '<leader>bd', function() require('snacks').bufdelete.delete() end, desc = 'Delete buffer' },
    { '<leader>bo', function() require('snacks').bufdelete.other() end, desc = 'Delete other buffers' },

    -- Smart rename
    { '<leader>rn', function() require('snacks').rename.rename_file() end, desc = 'Rename file' },

    -- Dismiss notifications
    { '<leader>nd', function() require('snacks').notifier.hide() end, desc = 'Dismiss all notifications' },
  },
  init = function()
    -- Override vim.notify with snacks notifier
    vim.notify = function(msg, level, opts)
      require('snacks').notifier.notify(msg, level, opts)
    end
  end,
}

-- Gitsigns - Git integration for buffers
-- https://github.com/lewis6991/gitsigns.nvim

return {
  'lewis6991/gitsigns.nvim',
  opts = {
    signs = {
      add = { text = '+' },
      change = { text = '~' },
      delete = { text = '_' },
      topdelete = { text = '‾' },
      changedelete = { text = '~' },
    },
  },
}

return {
  'kdheepak/lazygit.nvim',
  lazy = false,
  cmd = {
    'LazyGit',
    'LazyGitConfig',
    'LazyGitCurrentFile',
    'LazyGitFilter',
    'LazyGitFilterCurrentFile',
  },
  dependencies = {
    'nvim-lua/plenary.nvim',
  },
  keys = {
    { '<leader>lg', '<cmd>LazyGit<cr>', desc = 'LazyGit' },
    { '<leader>gc', '<cmd>LazyGitConfig<cr>', desc = 'LazyGit Config' },
    { '<leader>gf', '<cmd>LazyGitCurrentFile<cr>', desc = 'LazyGit Current File' },
  },
  config = function()
    vim.g.lazygit_floating_window_winblend = 0
    vim.g.lazygit_floating_window_scaling_factor = 0.9
    vim.g.lazygit_floating_window_border_chars = { '╭', '─', '╮', '│', '╯', '─', '╰', '│' }
    vim.g.lazygit_use_neovim_remote = 1
  end,
}

return {
  'sphamba/smear-cursor.nvim',
  opts = {
    smear_between_buffers = true,
    smear_between_neighbor_lines = true,
    smear_insert_mode = true,
  },
}

-- Flash.nvim - Navigate your code with search labels and Treesitter integration
-- https://github.com/folke/flash.nvim

return {
  'folke/flash.nvim',
  event = 'VeryLazy',
  opts = {
    -- Configure flash.nvim behavior
    modes = {
      -- Customize search mode
      search = {
        enabled = true,
        highlight = { backdrop = false },
      },
      -- Customize character mode
      char = {
        enabled = true,
        jump_labels = true,
      },
    },
    -- Treesitter mode configuration
    treesitter = {
      labels = 'abcdefghijklmnopqrstuvwxyz',
      jump = { pos = 'range', autojump = true },
      search = { incremental = false },
      label = { before = true, after = true, style = 'inline' },
      highlight = {
        backdrop = false,
        matches = false,
      },
    },
    -- Label configuration
    label = {
      uppercase = false,
      rainbow = {
        enabled = false,
      },
    },
    -- Highlight configuration
    highlight = {
      backdrop = true,
      matches = false,
      priority = 5000,
      groups = {
        match = 'FlashMatch',
        current = 'FlashCurrent',
        backdrop = 'FlashBackdrop',
        label = 'FlashLabel',
      },
    },
    -- Action configuration
    action = nil,
    -- Pattern configuration
    pattern = '',
    -- Continue last search
    continue = false,
    -- Prompt configuration
    prompt = {
      enabled = true,
      prefix = { { '⚡', 'FlashPromptIcon' } },
    },
  },
  keys = {
    {
      's',
      mode = { 'n', 'x', 'o' },
      function()
        require('flash').jump()
      end,
      desc = 'Flash',
    },
    {
      'S',
      mode = { 'n', 'x', 'o' },
      function()
        require('flash').treesitter()
      end,
      desc = 'Flash Treesitter',
